toolArgs.file_text:
@page "/book-appointment"
@rendermode InteractiveServer
@using sv_60b1b6ff99564569b9157456eeced6be.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

@if (isSubmitted)
{
    <div class="alert alert-success mt-3">
        <strong>Appointment booked!</strong> A confirmation has been sent to @step1.Email.
    </div>
}
else
{
    <h5>Step 1: Patient Information</h5>
    <EditForm EditContext="step1Context" OnValidSubmit="HandleStep1Valid" FormName="step1">
        <DataAnnotationsValidator />
        <CustomValidator @ref="step1CustomValidator" />

        <div class="mb-3">
            <label class="form-label">Patient Name</label>
            <InputText class="form-control" @bind-Value="step1.PatientName" />
            <ValidationMessage For="() => step1.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="step1.Email" />
            <ValidationMessage For="() => step1.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="step1.Phone" />
            <ValidationMessage For="() => step1.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label">Insurance Provider</label>
            <InputSelect class="form-select" @bind-Value="step1.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => step1.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="submit" class="btn btn-primary">Next →</button>
        }
    </EditForm>

    @if (showStep2)
    {
        <hr />
        <h5>Step 2: Appointment Details</h5>
        <EditForm EditContext="step2Context" OnSubmit="HandleStep2Submit" FormName="step2">
            <DataAnnotationsValidator />
            <CustomValidator @ref="step2CustomValidator" />

            <div class="mb-3">
                <label class="form-label">Preferred Doctor</label>
                <InputSelect class="form-select" @bind-Value="step2.Doctor">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => step2.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label">Appointment Date</label>
                <InputDate class="form-control" @bind-Value="step2.AppointmentDate"
                           @bind-Value:after="OnDateChanged" />
                <ValidationMessage For="() => step2.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label">Time Slot</label>
                <InputSelect class="form-select" @bind-Value="step2.TimeSlot" disabled="@(!availableSlots.Any())">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                @if (!availableSlots.Any() && step2.Doctor != "" && step2.AppointmentDate.HasValue)
                {
                    <small class="text-muted">Loading slots...</small>
                }
                <ValidationMessage For="() => step2.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label">Reason for Visit</label>
                <InputTextArea class="form-control" @bind-Value="step2.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => step2.ReasonForVisit" />
            </div>

            <button type="submit" class="btn btn-success" disabled="@isProcessing">
                @(isProcessing ? "Checking Availability..." : "Check Availability & Book")
            </button>
            <button type="button" class="btn btn-outline-secondary ms-2" @onclick="GoBackToStep1">
                ← Back
            </button>
        </EditForm>
    }
}

@code {
    private Step1Model step1 = new();
    private Step2Model step2 = new();
    private EditContext step1Context = default!;
    private EditContext step2Context = default!;
    private CustomValidator? step1CustomValidator;
    private CustomValidator? step2CustomValidator;

    private bool showStep2;
    private bool isSubmitted;
    private bool isProcessing;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        step1Context = new EditContext(step1);
        step2Context = new EditContext(step2);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void HandleStep1Valid()
    {
        showStep2 = true;
    }

    private async Task HandleStep2Submit()
    {
        step2CustomValidator?.ClearErrors();

        if (!step2Context.Validate())
            return;

        // Future-date validation (annotation handles it, but double-check)
        if (step2.AppointmentDate.HasValue && step2.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
        {
            step2CustomValidator?.DisplayErrors(new Dictionary<string, List<string>>
            {
                [nameof(Step2Model.AppointmentDate)] = ["Appointment date must be in the future."]
            });
            return;
        }

        isProcessing = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                step1.Email!, step1.InsuranceProvider, step2.Doctor, step2.TimeSlot);

            if (errors.Count > 0)
            {
                // Route Email errors to step1's validator, others to step2
                var step1Errors = new Dictionary<string, List<string>>();
                var step2Errors = new Dictionary<string, List<string>>();

                foreach (var (field, messages) in errors)
                {
                    if (field == nameof(BookAppointmentModel.Email))
                        step1Errors[nameof(Step1Model.Email)] = messages;
                    else if (field == nameof(BookAppointmentModel.Doctor))
                        step2Errors[nameof(Step2Model.Doctor)] = messages;
                    else if (field == nameof(BookAppointmentModel.TimeSlot))
                        step2Errors[nameof(Step2Model.TimeSlot)] = messages;
                }

                if (step1Errors.Count > 0)
                    step1CustomValidator?.DisplayErrors(step1Errors);
                if (step2Errors.Count > 0)
                    step2CustomValidator?.DisplayErrors(step2Errors);

                return;
            }

            isSubmitted = true;
        }
        finally
        {
            isProcessing = false;
        }
    }

    private async Task OnDateChanged()
    {
        availableSlots = [];
        step2.TimeSlot = "";

        if (!string.IsNullOrEmpty(step2.Doctor) && step2.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableSlotsAsync(
                step2.Doctor, step2.AppointmentDate.Value);
        }
    }

    private void GoBackToStep1()
    {
        showStep2 = false;
    }
}

